// Mini Platformer Levels
// Static level data extracted for easy management and AI generation
//
// Each level object:
//   name     - Display label shown in-game HUD
//   sequence - Play order (sorted ascending at load time)
//   theme    - Visual theme key used by drawBackground() and collectibleSprite()
//   backgroundActors - Moving background objects for that level
//   grid     - 18 rows × N chars (96 standard, larger supported); tile codes: . # B C o O E V W Y L U S F H
//
// All level grid rows below are fully static string literals.

const STORM_FOUNDRY_SEGMENT = [
  "................................................................................................",
  "................................................................................................",
  "..............Y.................................................................................",
  ".............BBB.........................CCC.........................BBB........................",
  "................................................................................................",
  "..........C...........BBB....o...................BBB....C.................BBB.............U.....",
  ".....................BBB......................BBB..................BBB..........................",
  "...................................V............................................................",
  "...................................W.......................E....................................",
  "..................o.....................LLLL....................o...............................",
  ".....S.....................BBB..................BBB..................BBB........................",
  "............................................................BBB......................G....F.....",
  "...........BBB..................BBB..................BBB..................BBB...................",
  "................................................................................................",
  "......................o......................LLLLLLLL.................o.........................",
  ".......................LLLLLLLLLLLLLLLL.........................................................",
  "................................................................................................",
  "###########..#######.....####....#####....######....####....#####....######....####....#########"
];

function setGridChar(row, index, value) {
  if (index < 0 || index >= row.length) return row;
  return row.slice(0, index) + value + row.slice(index + 1);
}

function buildStormFoundry6xGrid() {
  const rows = STORM_FOUNDRY_SEGMENT.map(row => row.repeat(6));
  const out = rows.map(row => row.replace(/S/g, ".").replace(/F/g, "."));

  const segmentWidth = STORM_FOUNDRY_SEGMENT[0].length;
  const linkChars = ["a", "b", "c", "d", "e", "f"];

  const placeSegmentMarkers = (segment, markers) => {
    const offset = segment * segmentWidth;
    for (let i = 0; i < markers.length; i++) {
      const m = markers[i];
      out[m.y] = setGridChar(out[m.y], offset + m.x, m.ch);
    }
  };

  for (let segment = 0; segment < 6; segment++) {
    const linkCh = linkChars[segment] || "f";
    const markers = [{ x: 14, y: 1, ch: linkCh }];

    if (segment === 0) {
      markers.push(
        { x: 20, y: 4, ch: "A" },
        { x: 22, y: 4, ch: "=" },
        { x: 23, y: 4, ch: "=" },
        { x: 24, y: 4, ch: "=" },
        { x: 80, y: 4, ch: "A" },
        { x: 82, y: 4, ch: "=" },
        { x: 83, y: 4, ch: "=" },
        { x: 84, y: 4, ch: "=" },
        { x: 36, y: 7, ch: "J" },
        { x: 56, y: 7, ch: "J" }
      );
    } else if (segment === 1) {
      markers.push(
        { x: 24, y: 2, ch: "~" },
        { x: 22, y: 4, ch: "A" },
        { x: 24, y: 4, ch: "=" },
        { x: 25, y: 4, ch: "=" },
        { x: 26, y: 4, ch: "=" },
        { x: 76, y: 4, ch: "A" },
        { x: 78, y: 4, ch: "=" },
        { x: 79, y: 4, ch: "=" },
        { x: 80, y: 4, ch: "=" },
        { x: 34, y: 7, ch: "J" },
        { x: 58, y: 7, ch: "J" },
        { x: 82, y: 7, ch: "J" }
      );
    } else if (segment === 2) {
      markers.push(
        { x: 20, y: 2, ch: "~" },
        { x: 60, y: 10, ch: "K" },
        { x: 18, y: 4, ch: "A" },
        { x: 20, y: 4, ch: "=" },
        { x: 21, y: 4, ch: "=" },
        { x: 22, y: 4, ch: "=" },
        { x: 52, y: 4, ch: "A" },
        { x: 54, y: 4, ch: "=" },
        { x: 55, y: 4, ch: "=" },
        { x: 56, y: 4, ch: "=" },
        { x: 80, y: 4, ch: "A" },
        { x: 82, y: 4, ch: "=" },
        { x: 83, y: 4, ch: "=" },
        { x: 84, y: 4, ch: "=" },
        { x: 26, y: 7, ch: "J" },
        { x: 42, y: 7, ch: "J" },
        { x: 58, y: 7, ch: "J" }
      );
    } else if (segment === 3) {
      markers.push(
        { x: 18, y: 2, ch: "~" },
        { x: 72, y: 6, ch: "~" },
        { x: 58, y: 10, ch: "K" },
        { x: 30, y: 9, ch: "M" },
        { x: 16, y: 4, ch: "A" },
        { x: 18, y: 4, ch: "=" },
        { x: 19, y: 4, ch: "=" },
        { x: 20, y: 4, ch: "=" },
        { x: 50, y: 4, ch: "A" },
        { x: 52, y: 4, ch: "=" },
        { x: 53, y: 4, ch: "=" },
        { x: 54, y: 4, ch: "=" },
        { x: 78, y: 4, ch: "A" },
        { x: 80, y: 4, ch: "=" },
        { x: 81, y: 4, ch: "=" },
        { x: 82, y: 4, ch: "=" },
        { x: 22, y: 7, ch: "J" },
        { x: 38, y: 7, ch: "J" },
        { x: 54, y: 7, ch: "J" },
        { x: 84, y: 7, ch: "J" }
      );
    } else if (segment === 4) {
      markers.push(
        { x: 16, y: 2, ch: "~" },
        { x: 72, y: 2, ch: "~" },
        { x: 62, y: 10, ch: "K" },
        { x: 44, y: 9, ch: "M" },
        { x: 14, y: 4, ch: "A" },
        { x: 16, y: 4, ch: "=" },
        { x: 17, y: 4, ch: "=" },
        { x: 18, y: 4, ch: "=" },
        { x: 46, y: 4, ch: "A" },
        { x: 48, y: 4, ch: "=" },
        { x: 49, y: 4, ch: "=" },
        { x: 50, y: 4, ch: "=" },
        { x: 76, y: 4, ch: "A" },
        { x: 78, y: 4, ch: "=" },
        { x: 79, y: 4, ch: "=" },
        { x: 80, y: 4, ch: "=" },
        { x: 86, y: 4, ch: "A" },
        { x: 88, y: 4, ch: "=" },
        { x: 89, y: 4, ch: "=" },
        { x: 90, y: 4, ch: "=" },
        { x: 20, y: 7, ch: "J" },
        { x: 34, y: 7, ch: "J" },
        { x: 50, y: 7, ch: "J" },
        { x: 84, y: 7, ch: "J" }
      );
    } else {
      markers.push(
        { x: 12, y: 2, ch: "~" },
        { x: 68, y: 2, ch: "~" },
        { x: 40, y: 10, ch: "K" },
        { x: 70, y: 9, ch: "M" },
        { x: 12, y: 4, ch: "A" },
        { x: 14, y: 4, ch: "=" },
        { x: 15, y: 4, ch: "=" },
        { x: 16, y: 4, ch: "=" },
        { x: 44, y: 4, ch: "A" },
        { x: 46, y: 4, ch: "=" },
        { x: 47, y: 4, ch: "=" },
        { x: 48, y: 4, ch: "=" },
        { x: 74, y: 4, ch: "A" },
        { x: 76, y: 4, ch: "=" },
        { x: 77, y: 4, ch: "=" },
        { x: 78, y: 4, ch: "=" },
        { x: 84, y: 4, ch: "A" },
        { x: 86, y: 4, ch: "=" },
        { x: 87, y: 4, ch: "=" },
        { x: 88, y: 4, ch: "=" },
        { x: 18, y: 7, ch: "J" },
        { x: 32, y: 7, ch: "J" },
        { x: 48, y: 7, ch: "J" },
        { x: 74, y: 7, ch: "J" },
        { x: 88, y: 7, ch: "J" }
      );
    }

    placeSegmentMarkers(segment, markers);
  }

  out[10] = setGridChar(out[10], 5, "S");
  out[11] = setGridChar(out[11], out[11].length - 6, "F");
  return out;
}

